fun topologicalSortParallel(data: IntArray): Int {
    val n = data[0]
    val m = data[1]

    val adj = Array(n) { mutableListOf<Int>() }
    val indegree = IntArray(n)

    var idx = 2
    repeat(m) {
        val u = data[idx]; val v = data[idx + 1]
        adj[u].add(v)
        indegree[v]++
        idx += 2
    }

    var queue = mutableListOf<Int>()
    for (i in 0 until n) {
        if (indegree[i] == 0) queue.add(i)
    }

    var rounds = 0
    var processed = 0

    while (queue.isNotEmpty()) {
        val nextQueue = mutableListOf<Int>()
        for (node in queue) {
            processed++
            for (neighbor in adj[node]) {
                indegree[neighbor]--
                if (indegree[neighbor] == 0) {
                    nextQueue.add(neighbor)
                }
            }
        }
        queue = nextQueue
        rounds++
    }

    return if (processed == n) rounds else -1
}

use std::collections::VecDeque;

pub fn topological_sort_parallel(data: &[i32]) -> i32 {
    let n = data[0] as usize;
    let m = data[1] as usize;

    let mut adj = vec![vec![]; n];
    let mut indegree = vec![0i32; n];

    let mut idx = 2;
    for _ in 0..m {
        let u = data[idx] as usize;
        let v = data[idx + 1] as usize;
        adj[u].push(v);
        indegree[v] += 1;
        idx += 2;
    }

    let mut queue: VecDeque<usize> = VecDeque::new();
    for i in 0..n {
        if indegree[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut rounds = 0;
    let mut processed = 0;

    while !queue.is_empty() {
        let size = queue.len();
        for _ in 0..size {
            let node = queue.pop_front().unwrap();
            processed += 1;
            for &neighbor in &adj[node] {
                indegree[neighbor] -= 1;
                if indegree[neighbor] == 0 {
                    queue.push_back(neighbor);
                }
            }
        }
        rounds += 1;
    }

    if processed == n as i32 { rounds } else { -1 }
}

import scala.collection.mutable

object TopologicalSortParallel {

  def topologicalSortParallel(data: Array[Int]): Int = {
    val n = data(0)
    val m = data(1)

    val adj = Array.fill(n)(mutable.ListBuffer[Int]())
    val indegree = new Array[Int](n)

    var idx = 2
    for (_ <- 0 until m) {
      val u = data(idx); val v = data(idx + 1)
      adj(u) += v
      indegree(v) += 1
      idx += 2
    }

    var queue = mutable.Queue[Int]()
    for (i <- 0 until n) {
      if (indegree(i) == 0) queue.enqueue(i)
    }

    var rounds = 0
    var processed = 0

    while (queue.nonEmpty) {
      val size = queue.size
      for (_ <- 0 until size) {
        val node = queue.dequeue()
        processed += 1
        for (neighbor <- adj(node)) {
          indegree(neighbor) -= 1
          if (indegree(neighbor) == 0) {
            queue.enqueue(neighbor)
          }
        }
      }
      rounds += 1
    }

    if (processed == n) rounds else -1
  }
}

func topologicalSortParallel(_ data: [Int]) -> Int {
    let n = data[0]
    let m = data[1]

    var adj = [[Int]](repeating: [], count: n)
    var indegree = [Int](repeating: 0, count: n)

    var idx = 2
    for _ in 0..<m {
        let u = data[idx], v = data[idx + 1]
        adj[u].append(v)
        indegree[v] += 1
        idx += 2
    }

    var queue = [Int]()
    for i in 0..<n {
        if indegree[i] == 0 { queue.append(i) }
    }

    var rounds = 0
    var processed = 0

    while !queue.isEmpty {
        var nextQueue = [Int]()
        for node in queue {
            processed += 1
            for neighbor in adj[node] {
                indegree[neighbor] -= 1
                if indegree[neighbor] == 0 {
                    nextQueue.append(neighbor)
                }
            }
        }
        queue = nextQueue
        rounds += 1
    }

    return processed == n ? rounds : -1
}

export function topologicalSortParallel(data: number[]): number {
    const n = data[0];
    const m = data[1];

    const adj: number[][] = Array.from({ length: n }, () => []);
    const indegree = new Array(n).fill(0);

    let idx = 2;
    for (let e = 0; e < m; e++) {
        const u = data[idx], v = data[idx + 1];
        adj[u].push(v);
        indegree[v]++;
        idx += 2;
    }

    let queue: number[] = [];
    for (let i = 0; i < n; i++) {
        if (indegree[i] === 0) queue.push(i);
    }

    let rounds = 0;
    let processed = 0;

    while (queue.length > 0) {
        const nextQueue: number[] = [];
        for (const node of queue) {
            processed++;
            for (const neighbor of adj[node]) {
                indegree[neighbor]--;
                if (indegree[neighbor] === 0) {
                    nextQueue.push(neighbor);
                }
            }
        }
        queue = nextQueue;
        rounds++;
    }

    return processed === n ? rounds : -1;
}
